using Microsoft.EntityFrameworkCore;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF Core 9 writes "$type" by default instead of "Discriminator".
            // Existing 500K documents use "Discriminator", and direct SQL queries
            // reference c.Discriminator, so we must keep the old name.
            b.HasDiscriminator<string>("Discriminator").HasValue("Product");

            // BREAKING CHANGE 2 — id value no longer includes the discriminator.
            // EF Core 8 synthesized id as "Product|123"; EF Core 9 uses just "123".
            // Existing documents carry the old format, so we must preserve it.
            b.HasIdProperty(p => "Product|" + p.Id);

            // BREAKING CHANGE 3 — HasIndex is ignored by the Cosmos provider
            // (Cosmos manages indexes at the container level, not via EF).
            // Removed: b.HasIndex(p => p.Sku);
        });
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = string.Empty;
}

