class CosmosQuery
{
    // BREAKING CHANGE 4 — Synchronous I/O removed.
    // The EF Core 9 Cosmos provider no longer supports sync APIs such as
    // ToList(), First(), SaveChanges(), etc.  All data-access calls must be async.
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator" as the
        // discriminator property name in ProductContext.OnModelCreating.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // ToList() → ToListAsync()
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

